// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Get server config (placeholder — Story 6.10)
	// (GET /admin/config)
	GetAdminConfig(ctx context.Context, request GetAdminConfigRequestObject) (GetAdminConfigResponseObject, error)
	// Get metrics (placeholder — Story 6.10)
	// (GET /admin/metrics)
	GetAdminMetrics(ctx context.Context, request GetAdminMetricsRequestObject) (GetAdminMetricsResponseObject, error)
	// List rooms (placeholder — Story 6.7)
	// (GET /admin/rooms)
	ListAdminRooms(ctx context.Context, request ListAdminRoomsRequestObject) (ListAdminRoomsResponseObject, error)
	// List users (instance_admin required)
	// (GET /admin/users)
	ListAdminUsers(ctx context.Context, request ListAdminUsersRequestObject) (ListAdminUsersResponseObject, error)
	// Get single user (instance_admin required)
	// (GET /admin/users/{userId})
	GetAdminUser(ctx context.Context, request GetAdminUserRequestObject) (GetAdminUserResponseObject, error)
	// Deactivate user account (instance_admin required)
	// (POST /admin/users/{userId}/deactivate)
	DeactivateAdminUser(ctx context.Context, request DeactivateAdminUserRequestObject) (DeactivateAdminUserResponseObject, error)
	// Reactivate user account (instance_admin required)
	// (POST /admin/users/{userId}/reactivate)
	ReactivateAdminUser(ctx context.Context, request ReactivateAdminUserRequestObject) (ReactivateAdminUserResponseObject, error)
	// Grant or revoke a role override for a user (instance_admin required)
	// (POST /admin/users/{userId}/roles)
	AssignAdminUserRole(ctx context.Context, request AssignAdminUserRoleRequestObject) (AssignAdminUserRoleResponseObject, error)
	// List compliance access requests (placeholder — Story 6.x)
	// (GET /compliance/access-requests)
	ListComplianceAccessRequests(ctx context.Context, request ListComplianceAccessRequestsRequestObject) (ListComplianceAccessRequestsResponseObject, error)
	// Health check (unauthenticated)
	// (GET /health)
	GetHealth(ctx context.Context, request GetHealthRequestObject) (GetHealthResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

